package org.eclipse.rdf4j.query.algebra.evaluation.sketch;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.Resource;
import org.eclipse.rdf4j.model.Statement;
import org.eclipse.rdf4j.model.Value;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.Join;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.Var;
import org.junit.jupiter.api.Test;

class SketchBasedJoinEstimatorCrossComponentJoinRegressionTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();

	@Test
	void estimateRemainsPositiveWhenJoiningObjectBindingsToSubjectBindings() {
		IRI locatedAt = VF.createIRI("urn:locatedAt");
		IRI hasName = VF.createIRI("urn:hasName");
		Resource copy1 = VF.createIRI("urn:copy:1");
		Resource copy2 = VF.createIRI("urn:copy:2");
		Resource copy3 = VF.createIRI("urn:copy:3");
		Resource branch1 = VF.createIRI("urn:branch:1");
		Resource branch2 = VF.createIRI("urn:branch:2");

		StubSketchStatementSource store = new StubSketchStatementSource();
		store.add(st(copy1, locatedAt, branch1));
		store.add(st(copy2, locatedAt, branch1));
		store.add(st(copy3, locatedAt, branch2));
		store.add(st(branch1, hasName, VF.createLiteral("Branch 1")));
		store.add(st(branch2, hasName, VF.createLiteral("Branch 2")));

		SketchBasedJoinEstimator estimator = new SketchBasedJoinEstimator(store, config());
		estimator.rebuild();

		double directJoinEstimate = estimator.estimate(SketchBasedJoinEstimator.Component.O, null,
				locatedAt.stringValue(), null, null)
				.join(SketchBasedJoinEstimator.Component.S, null, hasName.stringValue(), null, null)
				.estimate();
		double plannerJoinEstimate = estimator.cardinality(new Join(
				new StatementPattern(Var.of("copy"), Var.of("locatedAt", locatedAt), Var.of("branch")),
				new StatementPattern(Var.of("branch"), Var.of("hasName", hasName), Var.of("branchName"))));

		assertEquals(3.0d, directJoinEstimate, 0.0d,
				"Direct join estimate should preserve shared branch bindings across O->S joins");
		assertTrue(plannerJoinEstimate > 0.0d,
				"Planner join estimate should stay positive for object-to-subject chains");
	}

	@Test
	void selectiveBridgeDoesNotCarryUnconditionedOtherSideSketch() {
		IRI selected = VF.createIRI("urn:selected");
		IRI bridge = VF.createIRI("urn:bridge");
		IRI target = VF.createIRI("urn:target");
		Resource marker = VF.createIRI("urn:marker");

		StubSketchStatementSource store = new StubSketchStatementSource();
		for (int i = 0; i < 1000; i++) {
			Resource a = VF.createIRI("urn:a" + i);
			Resource b = VF.createIRI("urn:b" + i);
			store.add(st(a, bridge, b));
			store.add(st(b, target, marker));
		}
		store.add(st(VF.createIRI("urn:a0"), selected, marker));

		SketchBasedJoinEstimator estimator = new SketchBasedJoinEstimator(store, config());
		estimator.rebuild();

		StatementPattern left = new StatementPattern(Var.of("a"), Var.of("selected", selected),
				Var.of("marker1", marker));
		StatementPattern bridgePattern = new StatementPattern(Var.of("a"), Var.of("bridge", bridge), Var.of("b"));
		StatementPattern right = new StatementPattern(Var.of("b"), Var.of("target", target),
				Var.of("marker2", marker));

		double estimate = estimator.cardinality(new Join(new Join(left, bridgePattern), right));

		assertEquals(1.0d, estimate, 0.0d,
				"Bridge output sketches should be conditioned by the selective join on the other bridge variable");
	}

	private static SketchBasedJoinEstimator.Config config() {
		return SketchBasedJoinEstimator.Config.defaults()
				.withNominalEntries(64)
				.withThrottleEveryN(1)
				.withThrottleMillis(0)
				.withRefreshSleepMillis(5);
	}

	private static Statement st(Resource s, IRI p, Value o) {
		return VF.createStatement(s, p, o);
	}
}
